// Aggregate the active market by sector. This message is the seed of
// the monthly per-sector price report (the product for real-estate
// agencies): same numbers, same query, nicer formatting later.
const rows = $input.all().map(item => item.json).filter(row => row.sector);
const since = Date.now() - 7 * 24 * 3600 * 1000;

const porSector = {};
for (const row of rows) {
  const s = (porSector[row.sector] ??= { n: 0, suma: 0, min: Infinity, max: 0, nuevos: 0 });
  const precio = Number(row.price_dop);
  s.n += 1;
  s.suma += precio;
  s.min = Math.min(s.min, precio);
  s.max = Math.max(s.max, precio);
  if (new Date(row.first_seen).getTime() >= since) s.nuevos += 1;
}

const fmt = (n) => 'RD$' + Math.round(n).toLocaleString('es-DO');
const lineas = Object.entries(porSector)
  .sort((a, b) => b[1].n - a[1].n)
  .map(([sector, s]) =>
    `• ${sector}: ${s.n} activos (${s.nuevos} nuevos) · promedio ${fmt(s.suma / s.n)} · rango ${fmt(s.min)}–${fmt(s.max)}`
  );
const nuevos = Object.values(porSector).reduce((acc, s) => acc + s.nuevos, 0);

const mensaje =
  `📊 Mercado de alquileres SD — ${rows.length} listados activos, ${nuevos} nuevos esta semana.\n\n` +
  (lineas.length ? lineas.join('\n') : 'Sin datos todavía: corre discovery.py y agent.py --from-queue.');
return [{ json: { mensaje } }];
